public struct FfiConverterTypeTransferObserver: FfiConverter {
    fileprivate static let handleMap = UniffiHandleMap<TransferObserver>()

    typealias FfiType = UInt64
    typealias SwiftType = TransferObserver

    public static func lift(_ handle: UInt64) throws -> TransferObserver {
        if ((handle & 1) == 0) {
            // Rust-generated handle, construct a new class that uses the handle to implement the
            // interface
            return TransferObserverImpl(unsafeFromHandle: handle)
        } else {
            // Swift-generated handle, get the object from the handle map
            return try handleMap.remove(handle: handle)
        }
    }

    public static func lower(_ value: TransferObserver) -> UInt64 {
         if let rustImpl = value as? TransferObserverImpl {
             // Rust-implemented object.  Clone the handle and return it
            return rustImpl.uniffiCloneHandle()
         } else {
            // Swift object, generate a new vtable handle and return that.
            return handleMap.insert(obj: value)
         }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TransferObserver {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: TransferObserver, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


